import React from 'react';
import { useSelector, useDispatch } from 'react-redux';
import { increaseCount, decreaseCount, removeFromCart, clearCart } from '../../store/slices/cartSlice';
import { getImageUrl } from '../../utils/api';
import Button from '../../components/UI/Button';
import s from './CartPage.module.css';

const CartPage = () => {
  const dispatch = useDispatch();
  const cartItems = useSelector(state => state.cart.items);

  // Считаем общую сумму
  const total = cartItems.reduce((sum, item) => sum + item.price * item.count, 0);

  if (cartItems.length === 0) {
    return <div className={s.container}>Ваша корзина пуста.</div>;
  }

  return (
    <div className={s.container}>
      <h1 className={s.title}>Корзина</h1>

      <div className={s.items}>
        {cartItems.map(item => (
          <div key={item.id} className={s.item}>
            <img src={getImageUrl(item.image)} alt={item.title} className={s.image} />

            <div className={s.info}>
              <h2 className={s.name}>{item.title}</h2>
              {item.originalPrice > item.price && (
                <p className={s.originalPrice}>{item.originalPrice} $</p>
              )}
              <p className={s.price}>{item.price} $</p>

              <div className={s.quantityBlock}>
                <Button onClick={() => dispatch(decreaseCount({ id: item.id }))}>-</Button>
                <span className={s.count}>{item.count}</span>
                <Button onClick={() => dispatch(increaseCount({ id: item.id }))}>+</Button>
              </div>

              <Button onClick={() => dispatch(removeFromCart({ id: item.id }))} type="secondary">
                Удалить
              </Button>
            </div>
          </div>
        ))}
      </div>

      <div className={s.summary}>
        <p className={s.total}>Итого: {total.toFixed(2)} $</p>
        <Button onClick={() => dispatch(clearCart())} type="primary">
          Очистить корзину
        </Button>
      </div>
    </div>
  );
};

export default CartPage;
